package com.vycepay.admin.api.v1;
import java.util.*; import com.vycepay.admin.api.v1.dto.AdminRequests.RoleRequest; import com.vycepay.admin.application.service.*; import com.vycepay.common.api.*; import jakarta.servlet.http.HttpServletRequest; import jakarta.validation.Valid; import org.springframework.http.ResponseEntity; import org.springframework.security.access.prepost.PreAuthorize; import org.springframework.web.bind.annotation.*;
/** Role and permission management APIs. */
@RestController @RequestMapping("/api/admin/v1/roles") @PreAuthorize("hasAuthority('PERM_admin:manage_roles')")
public class RoleController{private final AdminReadService r; private final AdminMutationService m; private final RateLimitService rateLimitService; public RoleController(AdminReadService r,AdminMutationService m,RateLimitService rateLimitService){this.r=r;this.m=m;this.rateLimitService=rateLimitService;} @GetMapping public ResponseEntity<ApiSuccessResponse<List<Map<String,Object>>>> list(){return ResponseEntity.ok(ApiSuccessResponses.ok("ROLES_OK","Roles",r.roles()));} @GetMapping("/permissions") public ResponseEntity<ApiSuccessResponse<List<Map<String,Object>>>> permissions(){return ResponseEntity.ok(ApiSuccessResponses.ok("PERMISSIONS_OK","Permissions",r.permissions()));} @GetMapping("/{id}") public ResponseEntity<ApiSuccessResponse<Map<String,Object>>> detail(@PathVariable Long id){return ResponseEntity.ok(ApiSuccessResponses.ok("ROLE_OK","Role",r.roleDetail(id)));} @PostMapping public ResponseEntity<ApiSuccessResponse<Map<String,Object>>> create(@Valid @RequestBody RoleRequest body,HttpServletRequest req){rateLimitService.check("mutation",req);Long id=m.createRole(body,req);return ResponseEntity.ok(ApiSuccessResponses.ok("ROLE_CREATED","Role created",Map.of("id",id)));} @PutMapping("/{id}") public ResponseEntity<ApiSuccessResponse<Void>> update(@PathVariable Long id,@Valid @RequestBody RoleRequest body,HttpServletRequest req){rateLimitService.check("mutation",req);m.updateRole(id,body,req);return ResponseEntity.ok(ApiSuccessResponses.ok("ROLE_UPDATED","Role updated"));} @DeleteMapping("/{id}") public ResponseEntity<ApiSuccessResponse<Void>> delete(@PathVariable Long id,HttpServletRequest req){rateLimitService.check("mutation",req);m.deleteRole(id,req);return ResponseEntity.ok(ApiSuccessResponses.ok("ROLE_DELETED","Role deleted"));}}
